import React, { useState } from "react";
import axios from "axios";

function NERPage() {
  const [text, setText] = useState("");
  const [entities, setEntities] = useState(null);
  const [error, setError] = useState("");

  const handleNER = async () => {
    try {
      setError("");
      setEntities(null);

      const res = await axios.post("http://localhost:3000/api/ner", {
        text: text,
      });

      setEntities(res.data);
    } catch (err) {
      console.error(err);
      setError("NER processing failed.");
    }
  };

  return (
    <div style={{ padding: "20px" }}>
      <h2>Named Entity Recognition (NER)</h2>

      <textarea
        rows={5}
        value={text}
        onChange={(e) => setText(e.target.value)}
        placeholder="Enter text for NER"
        style={{
          width: "100%",
          marginBottom: "10px",
          padding: "10px",
        }}
      />

      <br />
      <button onClick={handleNER}>Extract Entities</button>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {entities && (
        <div style={{ marginTop: "20px" }}>
          <h4>Detected Entities:</h4>
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr>
                <th style={{ border: "1px solid #ccc", padding: "8px" }}>Word</th>
                <th style={{ border: "1px solid #ccc", padding: "8px" }}>Entity</th>
                <th style={{ border: "1px solid #ccc", padding: "8px" }}>Score</th>
              </tr>
            </thead>
            <tbody>
              {entities.length > 0 ? (
                entities.map((ent, idx) => (
                  <tr key={idx}>
                    <td style={{ border: "1px solid #ccc", padding: "8px" }}>
                      {ent.word}
                    </td>
                    <td style={{ border: "1px solid #ccc", padding: "8px" }}>
                      {ent.entity_group}
                    </td>
                    <td style={{ border: "1px solid #ccc", padding: "8px" }}>
                      {ent.score?.toFixed(4)}
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={3} style={{ padding: "8px" }}>
                    No entities found.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default NERPage;
